  ('dietitian-moex-11452', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '近年來各醫院均積極進行體重控制活動，若某醫院營養師在評估該活動的成果時，表示有80%參加者在三個月的體重 控制活動中達到預期想要減重的體重重量，此種評價的呈現方式屬於： 效率（Efficiency）  效能（Effectiveness）  效果（Effort）  效力（Efficacy） （請接背面） 九十二年第二次專門職業及技術人員高等暨普通考試醫事人員考試、高等考試 全一張 中醫師考試、高等考試營養師考試、高等暨普通考試獸醫人員考試及九十二年 代號：11150 （背面） 專門職業及技術人員高等考試心理師考試、高等考試呼吸治療師考試試題 類    科： 營養師', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
